def connect_wifi():
    """Connect to WiFi network."""
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
        if not wlan.isconnected():
            raise RuntimeError("Failed to connect to WiFi")
    ip = wlan.ifconfig()[0]
    print("Connected. IP:", ip)
    return ip


def generate_nonce(length=16):
    """Generate a random nonce for security purposes."""
    return binascii.hexlify(os.urandom(length)).decode()


def compute_websocket_accept(key):
    """Compute Sec-WebSocket-Accept header value."""
    GUID = "258EAFA5-E914-47DA-95CA-5AB5CF11731D"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode()).digest()
    return binascii.b2a_base64(sha1_hash).decode().strip()


def validate_origin(headers):
    """Validate the Origin header to prevent unauthorized cross-origin connections."""
    origin = None
    for line in headers:
        if line.lower().startswith("origin:"):
            origin = line.split(":", 1)[1].strip()
            break

    if ALLOWED_ORIGINS is None:
        # In development, allow all origins but log warning
        print("WARNING: Origin validation disabled. Set ALLOWED_ORIGINS for production.")
        return True

    if origin is None:
        print("Rejected: No Origin header")
        return False

    if origin in ALLOWED_ORIGINS:
        return True

    print("Rejected origin:", origin)
    return False


def parse_http_request(data):
    """Parse HTTP upgrade request and return headers dict."""
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    headers = {}
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def validate_websocket_upgrade(request_line, headers):
    """Validate that this is a proper WebSocket upgrade request."""
    # Check request method and path
    parts = request_line.split()
    if len(parts) < 3 or parts[0] != "GET":
        return False, "Invalid HTTP method"

    # Only allow specific paths
    allowed_paths = ["/ws", "/", "/control"]
    if parts[1] not in allowed_paths:
        return False, "Invalid path: " + parts[1]

    # Check required WebSocket headers
    if headers.get("upgrade", "").lower() != "websocket":
        return False, "Missing or invalid Upgrade header"

    if "websocket" not in headers.get("connection", "").lower():
        return False, "Missing WebSocket in Connection header"

    if "sec-websocket-key" not in headers:
        return False, "Missing Sec-WebSocket-Key"

    # Validate WebSocket version
    version = headers.get("sec-websocket-version", "")
    if version != "13":
        return False, "Unsupported WebSocket version: " + version

    return True, "OK"


def send_http_error(client_sock, status_code, message):
    """Send an HTTP error response."""
    response = "HTTP/1.1 {} {}\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}".format(
        status_code, message, len(message), message
    )
    try:
        client_sock.send(response.encode())
    except Exception:
        pass


def perform_websocket_handshake(client_sock):
    """Perform WebSocket handshake with security validation."""
    try:
        client_sock.settimeout(5.0)
        data = client_sock.recv(1024)
        if not data:
            return False

        request_line, headers = parse_http_request(data)

        # Validate origin
        header_lines = data.decode("utf-8").split("\r\n")
        if not validate_origin(header_lines):
            send_http_error(client_sock, 403, "Forbidden: Invalid Origin")
            return False

        # Validate WebSocket upgrade request
        valid, reason = validate_websocket_upgrade(request_line, headers)
        if not valid:
            send_http_error(client_sock, 400, "Bad Request: " + reason)
            return False

        # Compute accept key
        ws_key = headers["sec-websocket-key"]
        accept_key = compute_websocket_accept(ws_key)

        # Generate a unique connection nonce for this session
        conn_nonce = generate_nonce(8)

        # Send handshake response
        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: {}\r\n"
            "X-Connection-ID: {}\r\n"
            "\r\n"
        ).format(accept_key, conn_nonce)

        client_sock.send(response.encode())
        client_sock.settimeout(0.1)
        return True

    except Exception as e:
        print("Handshake error:", e)
        return False


def decode_websocket_frame(data):
    """Decode a WebSocket frame. Returns (opcode, payload) or (None, None) on error."""
    if len(data) < 2:
        return None, None

    byte1 = data[0]
    byte2 = data[1]

    opcode = byte1 & 0x0F
    fin = (byte1 >> 7) & 1
    masked = (byte2 >> 7) & 1
    payload_length = byte2 & 0x7F

    # RFC 6455: client frames MUST be masked
    if not masked:
        print("Security: Received unmasked frame from client - rejecting")
        return None, None

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None
        payload_length = struct.unpack("!H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None
        payload_length = struct.unpack("!Q", data[2:10])[0]
        offset = 10

    # Limit payload size to prevent memory exhaustion
    MAX_PAYLOAD = 4096
    if payload_length > MAX_PAYLOAD:
        print("Security: Payload too large:", payload_length)
        return None, None

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_length:
        return None, None

    payload = bytearray(data[offset:offset + payload_length])

    if masked:
        for i in range(payload_length):
            payload[i] ^= mask[i % 4]

    return opcode, bytes(payload)


def encode_websocket_frame(data, opcode=0x01):
    """Encode data into a WebSocket frame (server frames are NOT masked)."""
    if isinstance(data, str):
        data = data.encode("utf-8")

    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    length = len(data)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack("!H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack("!Q", length))

    frame.extend(data)
    return bytes(frame)


def send_close_frame(client_sock, code=1000, reason=""):
    """Send a WebSocket close frame."""
    payload = struct.pack("!H", code) + reason.encode("utf-8")
    frame = encode_websocket_frame(payload, opcode=0x08)
    try:
        client_sock.send(frame)
    except Exception:
        pass


def send_pong(client_sock, payload):
    """Send a WebSocket pong frame."""
    frame = encode_websocket_frame(payload, opcode=0x0A)
    try:
        client_sock.send(frame)
    except Exception:
        pass


# Rate limiting per client
class RateLimiter:
    def __init__(self, max_requests=30, window_seconds=10):
        self.max_requests = max_requests
        self.window = window_seconds
        self.clients = {}

    def check(self, client_id):
        """Returns True if request is allowed, False if rate limited."""
        now = time.ticks_ms()
        if client_id not in self.clients:
            self.clients[client_id] = []

        # Clean old entries
        self.clients[client_id] = [
            t for t in self.clients[client_id]
            if time.ticks_diff(now, t) < self.window * 1000
        ]

        if len(self.clients[client_id]) >= self.max_requests:
            return False

        self.clients[client_id].append(now)
        return True

    def remove(self, client_id):
        """Remove client from rate limiter."""
        self.clients.pop(client_id, None)


rate_limiter = RateLimiter(max_requests=30, window_seconds=10)


# Command validation and sanitization
VALID_ACTIONS = {
    "turn_on", "turn_off", "toggle", "set_brightness",
    "get_status", "set_mode", "ping", "restart"
}

VALID_MODES = {"manual", "auto", "timer", "schedule"}


def sanitize_string(value, max_length=64):
    """Sanitize a string value."""
    if not isinstance(value, str):
        return None
    # Truncate and strip
    value = value[:max_length].strip()
    # Remove control characters
    value = "".join(c for c in value if ord(c) >= 32)
    return value


def validate_command(cmd):
    """Validate and sanitize incoming command. Returns (valid, sanitized_cmd, error)."""
    if not isinstance(cmd, dict):
        return False, None, "Command must be a JSON object"

    action = cmd.get("action")
    if action is None:
        return False, None, "Missing 'action' field"

    action = sanitize_string(str(action), 32)
    if action not in VALID_ACTIONS:
        return False, None, "Unknown action: {}".format(action)

    sanitized = {"action": action}

    # Validate action-specific parameters
    if action == "set_brightness":
        brightness = cmd.get("value")
        if brightness is None:
            return False, None, "set_brightness requires 'value' field"
        try:
            brightness = int(brightness)
        except (ValueError, TypeError):
            return False, None, "Brightness must be an integer"
        if not (0 <= brightness <= 100):
            return False, None, "Brightness must be 0-100"
        sanitized["value"] = brightness

    elif action == "set_mode":
        mode = cmd.get("mode")
        if mode is None:
            return False, None, "set_mode requires 'mode' field"
        mode = sanitize_string(str(mode), 16)
        if mode not in VALID_MODES:
            return False, None, "Invalid mode: {}".format(mode)
        sanitized["mode"] = mode

    return True, sanitized, None


def handle_command(cmd):
    """Process a validated command and return response."""
    action = cmd["action"]
    response = {"status": "ok", "action": action}

    try:
        if action == "turn_on":
            device_state["power"] = True
            relay.value(1)
            led.value(1)
            response["power"] = True

        elif action == "turn_off":
            device_state["power"] = False
            relay.value(0)
            led.value(0)
            response["power"] = False

        elif action == "toggle":
            device_state["power"] = not device_state["power"]
            relay.value(1 if device_state["power"] else 0)
            led.value(1 if device_state["power"] else 0)
            response["power"] = device_state["power"]

        elif action == "set_brightness":
            value = cmd["value"]
            device_state["brightness"] = value
            # If using PWM for LED brightness
            response["brightness"] = value

        elif action == "set_mode":
            mode = cmd["mode"]
            device_state["mode"] = mode
            response["mode"] = mode

        elif action == "get_status":
            device_state["uptime"] = time.ticks_ms() // 1000
            response["state"] = device_state.copy()

        elif action == "ping":
            response["pong"] = True
            response["timestamp"] = time.ticks_ms()

        elif action == "restart":
            response["message"] = "Restarting in 2 seconds..."
            # Schedule restart (handled after sending response)
            response["_restart"] = True

    except Exception as e:
        response = {"status": "error", "action": action, "message": str(e)}

    return response


class WebSocketClient:
    """Represents a connected WebSocket client."""

    def __init__(self, sock, addr):
        self.sock = sock
        self.addr = addr
        self.client_id = "{}:{}".format(addr[0], addr[1])
        self.connected = True
        self.last_ping = time.ticks_ms()
        self.authenticated = False  # For future auth support
        self.buffer = bytearray()

    def close(self):
        """Close the client connection."""
        self.connected = False
        try:
            send_close_frame(self.sock, 1000, "Goodbye")
        except Exception:
            pass
        try:
            self.sock.close()
        except Exception:
            pass
        rate_limiter.remove(self.client_id)


class WebSocketServer:
    """MicroPython WebSocket server for ESP32 IoT devices."""

    def __init__(self, host, port):
        self.host = host
        self.port = port
        self.server_sock = None
        self.clients = []
        self.running = False
        self.ping_interval = 30000  # 30 seconds
        self.ping_timeout = 10000   # 10 seconds

    def start(self):
        """Start the WebSocket server."""
        self.server_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_sock.bind((self.host, self.port))
        self.server_sock.listen(MAX_CLIENTS)
        self.server_sock.settimeout(0.1)
        self.running = True
        print("WebSocket server started on ws://{}:{}".format(self.host, self.port))
        print("Accepting connections on paths: /ws, /, /control")

    def stop(self):
        """Stop the server and disconnect all clients."""
        self.running = False
        for client in self.clients:
            client.close()
        self.clients.clear()
        if self.server_sock:
            self.server_sock.close()
        print("Server stopped")

    def accept_new_connections(self):
        """Accept new incoming connections."""
        try:
            client_sock, addr = self.server_sock.accept()
            print("New connection from:", addr)

            # Check max clients
            if len(self.clients) >= MAX_CLIENTS:
                print("Max clients reached, rejecting:", addr)
                send_http_error(client_sock, 503, "Server Full")
                client_sock.close()
                return

            # Perform WebSocket handshake with validation
            if perform_websocket_handshake(client_sock):
                client = WebSocketClient(client_sock, addr)
                self.clients.append(client)
                print("WebSocket client connected:", client.client_id)

                # Send welcome message with device state
                welcome = {
                    "type": "welcome",
                    "message": "Connected to ESP32 IoT Controller",
                    "state": device_state.copy(),
                    "available_actions": list(VALID_ACTIONS)
                }
                self.send_to_client(client, json.dumps(welcome))
            else:
                print("Handshake failed for:", addr)
                client_sock.close()

        except OSError:
            pass  # No pending connections (timeout)

    def receive_from_client(self, client):
        """Receive and process data from a client."""
        try:
            data = client.sock.recv(4096)
            if not data:
                return False

            opcode, payload = decode_websocket_frame(data)

            if opcode is None:
                print("Invalid frame from:", client.client_id)
                return False

            # Handle close frame
            if opcode == 0x08:
                print("Close frame from:", client.client_id)
                return False

            # Handle ping frame
            if opcode == 0x09:
                send_pong(client.sock, payload)
                client.last_ping = time.ticks_ms()
                return True

            # Handle pong frame
            if opcode == 0x0A:
                client.last_ping = time.ticks_ms()
                return True

            # Handle text frame
            if opcode == 0x01:
                return self.process_message(client, payload)

            # Handle binary frame (not supported)
            if opcode == 0x02:
                error_resp = json.dumps({
                    "status": "error",
                    "message": "Binary frames not supported"
                })
                self.send_to_client(client, error_resp)
                return True

            return True

        except OSError as e:
            if e.args[0] == 11:  # EAGAIN - no data available
                return True
            return False
        except Exception as e:
            print("Receive error from {}: {}".format(client.client_id, e))
            return False

    def process_message(self, client, payload):
        """Process a text message from a client."""
        # Rate limiting
        if not rate_limiter.check(client.client_id):
            error_resp = json.dumps({
                "status": "error",
                "message": "Rate limit exceeded. Please slow down."
            })
            self.send_to_client(client, error_resp)
            print("Rate limited:", client.client_id)
            return True

        try:
            message = payload.decode("utf-8")
        except UnicodeError:
            error_resp = json.dumps({
                "status": "error",
                "message": "Invalid UTF-8 encoding"
            })
            self.send_to_client(client, error_resp)
            return True

        # Parse JSON
        try:
            cmd = json.loads(message)
        except (ValueError, TypeError):
            error_resp = json.dumps({
                "status": "error",
                "message": "Invalid JSON format"
            })
            self.send_to_client(client, error_resp)
            return True

        # Validate command
        valid, sanitized_cmd, error = validate_command(cmd)
        if not valid:
            error_resp = json.dumps({
                "status": "error",
                "message": error
            })
            self.send_to_client(client, error_resp)
            return True

        # Handle command
        print("Command from {}: {}".format(client.client_id, sanitized_cmd))
        response = handle_command(sanitized_cmd)

        # Check for restart flag
        needs_restart = response.pop("_restart", False)

        # Send response to requesting client
        self.send_to_client(client, json.dumps(response))

        # Broadcast state changes to all clients
        if sanitized_cmd["action"] in ("turn_on", "turn_off", "toggle", "set_brightness", "set_mode"):
            broadcast = {
                "type": "state_update",
                "source": client.client_id,
                "state": device_state.copy()
            }
            self.broadcast(json.dumps(broadcast), exclude=client)

        # Handle restart
        if needs_restart:
            time.sleep(2)
            machine.reset()

        return True

    def send_to_client(self, client, message):
        """Send a message to a specific client."""
        try:
            frame = encode_websocket_frame(message)
            client.sock.send(frame)
            return True
        except Exception as e:
            print("Send error to {}: {}".format(client.client_id, e))
            client.connected = False
            return False

    def broadcast(self, message, exclude=None):
        """Broadcast a message to all connected clients."""
        for client in self.clients:
            if client.connected and client != exclude:
                self.send_to_client(client, message)

    def check_client_health(self):
        """Send pings and remove dead clients."""
        now = time.ticks_ms()
        for client in self.clients[:]:
            # Check if client has timed out
            if time.ticks_diff(now, client.last_ping) > (self.ping_interval + self.ping_timeout):
                print("Client timed out:", client.client_id)
                client.close()
                self.clients.remove(client)
                continue

            # Send ping if interval elapsed
            if time.ticks_diff(now, client.last_ping) > self.ping_interval:
                try:
                    ping_frame = encode_websocket_frame(b"ping", opcode=0x09)
                    client.sock.send(ping_frame)
                except Exception:
                    client.close()
                    self.clients.remove(client)

    def cleanup_disconnected(self):
        """Remove disconnected clients."""
        for client in self.clients[:]:
            if not client.connected:
                print("Removing disconnected client:", client.client_id)
                client.close()
                self.clients.remove(client)

    def run(self):
        """Main server loop."""
        self.start()
        last_health_check = time.ticks_ms()

        try:
            while self.running:
                # Accept new connections
                self.accept_new_connections()

                # Process messages from connected clients
                for client in self.clients[:]:
                    if client.connected:
                        alive = self.receive_from_client(client)
                        if not alive:
                            client.close()

                # Periodic health check
                now = time.ticks_ms()
                if time.ticks_diff(now, last_health_check) > 10000:
                    self.check_client_health()
                    self.cleanup_disconnected()
                    last_health_check = now

                    # Collect garbage periodically
                    import gc
                    gc.collect()

        except KeyboardInterrupt:
            print("\nShutting down...")
        finally:
            self.stop()


