def start_http_server(host, port=80):
    """Start a simple HTTP server to serve the control page."""
    http_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    http_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    http_sock.bind((host, port))
    http_sock.listen(2)
    http_sock.settimeout(0.1)
    print("HTTP server started on http://{}:{}".format(host, port))
    return http_sock


def handle_http_request(http_sock):
    """Handle incoming HTTP requests for the control page."""
    try:
        client_sock, addr = http_sock.accept()
        client_sock.settimeout(2.0)
        request = client_sock.recv(1024)
        if request:
            # Simple security: only serve GET requests for known paths
            request_str = request.decode("utf-8", "ignore")
            first_line = request_str.split("\r\n")[0]
            if first_line.startswith("GET / ") or first_line.startswith("GET /index"):
                response = (
                    "HTTP/1.1 200 OK\r\n"
                    "Content-Type: text/html; charset=utf-8\r\n"
                    "Content-Length: {}\r\n"
                    "Cache-Control: no-store\r\n"
                    "X-Content-Type-Options: nosniff\r\n"
                    "X-Frame-Options: DENY\r\n"
                    "Connection: close\r\n"
                    "\r\n"
                    "{}"
                ).format(len(CONTROL_PAGE), CONTROL_PAGE)
                client_sock.send(response.encode())
            else:
                send_http_error(client_sock, 404, "Not Found")
        client_sock.close()
    except OSError:
        pass
    except Exception as e:
        print("HTTP error:", e)


def main():
    """Main entry point."""
    # Connect to WiFi
    ip = connect_wifi()

    # Start HTTP server for control page
    http_sock = start_http_server(ip, 80)

    # Create and start WebSocket server
    ws_server = WebSocketServer(ip, WS_PORT)

    print("\n" + "=" * 50)
    print("ESP32 IoT WebSocket Controller")
    print("=" * 50)
    print("Control Page: http://{}".format(ip))
    print("WebSocket:    ws://{}:{}/ws".format(ip, WS_PORT))
    print("=" * 50 + "\n")

    ws_server.start()

    try:
        last_health_check = time.ticks_ms()

        while ws_server.running:
            # Handle HTTP requests (serve control page)
            handle_http_request(http_sock)

            # Accept new WebSocket connections
            ws_server.accept_new_connections()

            # Process messages from connected clients
            for client in ws_server.clients[:]:
                if client.connected:
                    alive = ws_server.receive_from_client(client)
                    if not alive:
                        client.close()

            # Periodic maintenance
            now = time.ticks_ms()
            if time.ticks_diff(now, last_health_check) > 10000:
                ws_server.check_client_health()
                ws_server.cleanup_disconnected()
                last_health_check = now

                import gc
                gc.collect()

    except KeyboardInterrupt:
        print("\nShutting down...")
    finally:
        ws_server.stop()
        http_sock.close()
        print("Server stopped. Goodbye!")


if __name__ == "__main__":
    main()